const results = $input.item.json.web?.results || [];
const formatted = results.slice(0, 5).map(r => ({
  title: r.title,
  url: r.url,
  description: r.description
}));
return [{json: {search_results: formatted, count: formatted.length, query_date: new Date().toISOString()}}];

