parameters.jsCode:
const raw = $input.item.json.choices[0].message.content;
let ideas;
try {
  const match = raw.match(/```json([\s\S]*?)```/) || raw.match(/(\[[\s\S]*\])/);
  ideas = JSON.parse(match ? match[1].trim() : raw.trim());
  if (!Array.isArray(ideas)) ideas = [];
} catch(e) {
  console.log('Parse error:', e.message, '| Raw:', raw.substring(0, 200));
  ideas = [];
}
if (ideas.length === 0) {
  return [{json: {ideas: [], skipped: true, reason: 'no parseable ideas'}}];
}
return [{json: {ideas, count: ideas.length}}];
